import { jsx } from 'react/jsx-runtime';
import { classNames } from '../../helpers/classnames.js';

const Divider = ({ className, type = 'horizontal', isDecorative, ...props }) => {
    const baseClass = classNames('dsb_divider', `dsb_divider--${type}`, className);
    return isDecorative ? (jsx("div", { "data-testid": "Divider", "aria-hidden": "true", ...props, className: baseClass })) : (jsx("hr", { "data-testid": "Divider", role: "separator", ...props, className: baseClass }));
};

export { Divider };
